1	import { attachWordMenu } from "./word_menu";
2	
3	const PREF_KEYS = {
4		speed: "readaloud-playback-speed",
5		volume: "readaloud-volume",
6		collapsed: "readaloud-player-collapsed",
7	};
8	
9	function loadPrefs() {
10		return {
11			speed: Number.parseFloat(localStorage.getItem(PREF_KEYS.speed)) || 1,
12			volume: Number.parseFloat(localStorage.getItem(PREF_KEYS.volume)) || 1,
13			collapsed: localStorage.getItem(PREF_KEYS.collapsed) === "true",
14		};
15	}
16	
17	function persistPref(key, value) {
18		localStorage.setItem(PREF_KEYS[key], String(value));
19	}
20	
21	export const AudioPlayer = {
22		mounted() {
23			this.audio = document.getElementById("audio-element");
24			this.playPauseBtn = document.getElementById("play-pause-btn");
25			this.timeDisplay = document.getElementById("time-display");
26			this.textContainer = document.getElementById("chapter-text");
27			this.resyncBtn = document.getElementById("resync-btn");
28			this.timings = [];
29			this.currentWordIndex = -1;
30			this.autoScrollPaused = false;
31			this.isAutoScrolling = false;
32	
33			// Load and apply persisted prefs (collapsed/volume UI immediately;
34			// audio rate/volume reapplied on loadedmetadata for browser-quirk safety).
35			this.prefs = loadPrefs();
36			if (this.prefs.collapsed) this.el.classList.add("collapsed");
37	
38			const volSlider = this.el.querySelector("[data-volume-slider]");
39			if (volSlider) volSlider.value = this.prefs.volume;
40	
41			this.updateSpeedBadge(this.prefs.speed);
42	
43			// Load audio
44			this.audio.src = this.el.dataset.audioUrl;
45	
46			// Apply audio prefs now AND on every loadedmetadata. Some browsers reset
47			// playbackRate when src changes, so re-applying after metadata is the
48			// only robust restore point.
49			this.applyAudioPrefs();
50			this.audio.addEventListener("loadedmetadata", () => {
51				this.applyAudioPrefs();
52				this.updateTimeDisplay();
53			});
54			this.audio.addEventListener("durationchange", () =>
55				this.updateTimeDisplay(),
56			);
57	
58			// Load word-level timings; word menu attaches once timings are available.
59			fetch(this.el.dataset.timingsUrl)
60				.then((r) => r.json())
61				.then((data) => {
62					this.timings = data.timings || [];
63					this._wordMenuCleanup = attachWordMenu(this.textContainer);
64				});
65	
66			// Restore position
67			const initialMs = Number.parseInt(
68				this.el.dataset.initialPosition || "0",
69				10,
70			);
71			if (initialMs > 0) {
72				this.audio.addEventListener(
73					"loadedmetadata",
74					() => {
75						this.audio.currentTime = initialMs / 1000;
76					},
77					{ once: true },
78				);
79			}
80	
81			// Play/pause button
82			this.playPauseBtn.addEventListener("click", () => this.togglePlayback());
83	
84			// Skip back/forward buttons
85			const skipBack = this.el.querySelector("[data-skip-back]");
86			const skipFwd = this.el.querySelector("[data-skip-forward]");
87			if (skipBack)
88				skipBack.addEventListener("click", () => {
89					this.audio.currentTime = Math.max(0, this.audio.currentTime - 10);
90				});
91			if (skipFwd)
92				skipFwd.addEventListener("click", () => {
93					this.audio.currentTime = Math.min(
94						this.audio.duration || Number.POSITIVE_INFINITY,
95						this.audio.currentTime + 10,
96					);
97				});
98	
99			// Collapse toggle
100			const collapseToggle = this.el.querySelector("[data-collapse-toggle]");
101			if (collapseToggle) {
102				collapseToggle.addEventListener("click", () => {
103					const isCollapsed = this.el.classList.toggle("collapsed");
104					this.prefs.collapsed = isCollapsed;
105					persistPref("collapsed", isCollapsed);
106				});
107			}
108	
109			// Volume slider
110			if (volSlider) {
111				volSlider.addEventListener("input", () => {
112					const vol = Number.parseFloat(volSlider.value);
113					this.prefs.volume = vol;
114					this.audio.volume = vol;
115					persistPref("volume", vol);
116				});
117			}
118	
119			// Scrubber: main + mini
120			this._scrubberCleanups = [];
121			const scrubber = this.el.querySelector("[data-scrubber]");
122			if (scrubber) this.setupScrubber(scrubber);
123			const scrubberMini = this.el.querySelector("[data-scrubber-mini]");
124			if (scrubberMini) this.setupScrubber(scrubberMini);
125	
126			// Time update: progress + time display + position reporting (low frequency)
127			this.audio.addEventListener("timeupdate", () => {
128				if (!this.audio.duration) return;
129				const pct = (this.audio.currentTime / this.audio.duration) * 100;
130	
131				const fill = this.el.querySelector("[data-progress-fill]");
132				if (fill) fill.style.width = `${pct}%`;
133				const fillMini = this.el.querySelector("[data-progress-fill-mini]");
134				if (fillMini) fillMini.style.width = `${pct}%`;
135	
136				this.updateTimeDisplay();
137	
138				// Throttled position report (every ~5s of audio time)
139				const nowMs = Math.round(this.audio.currentTime * 1000);
140				if (
141					!this._lastReportedMs ||
142					Math.abs(nowMs - this._lastReportedMs) >= 5000
143				) {
144					this._lastReportedMs = nowMs;
145					this.pushEvent("audio_position", { position_ms: nowMs });
146				}
147			});
148	
149			// High-frequency word highlighting via requestAnimationFrame (60fps)
150			this._rafId = null;
151			this._startHighlightLoop = () => {
152				const tick = () => {
153					if (this.audio && !this.audio.paused) {
154						this.highlightWord(this.audio.currentTime * 1000);
155						this._rafId = requestAnimationFrame(tick);
156					}
157				};
158				this._rafId = requestAnimationFrame(tick);
159			};
160			this._stopHighlightLoop = () => {
161				if (this._rafId) {
162					cancelAnimationFrame(this._rafId);
163					this._rafId = null;
164				}
165			};
166			this.audio.addEventListener("play", this._startHighlightLoop);
167			this.audio.addEventListener("pause", this._stopHighlightLoop);
168			this.audio.addEventListener("ended", this._stopHighlightLoop);
169	
170			// Play/pause state
171			this.audio.addEventListener("play", () => {
172				this.playPauseBtn.innerHTML = "&#10074;&#10074;";
173				if (this.textContainer) this.textContainer.dataset.audioPlaying = "true";
174			});
175	
176			this.audio.addEventListener("pause", () => {
177				this.playPauseBtn.innerHTML = "&#9654;";
178				if (this.textContainer) this.textContainer.dataset.audioPlaying = "false";
179				this.pushEvent("audio_position", {
180					position_ms: Math.round(this.audio.currentTime * 1000),
181				});
182			});
183	
184			// Auto-advance
185			this.audio.addEventListener("ended", () => {
186				const settings = this.loadReaderSettings();
187				if (settings.autoNextChapter) {
188					this.pushEvent("next_chapter", {});
189				}
190			});
191	
192			// Re-sync button
193			if (this.resyncBtn) {
194				this.resyncBtn.addEventListener("click", () => {
195					this.autoScrollPaused = false;
196					this.resyncBtn.classList.add("hidden");
197					if (this.currentWordIndex >= 0 && this.textContainer) {
198						const el = this.textContainer.querySelector(
199							`[data-word-index="${this.currentWordIndex}"]`,
200						);
201						if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
202					}
203				});
204			}
205	
206			// Manual scroll detection from ScrollTracker
207			this._manualScrollHandler = () => {
208				if (!this.audio.paused && !this.isAutoScrolling) {
209					this.autoScrollPaused = true;
210					if (this.resyncBtn) this.resyncBtn.classList.remove("hidden");
211				}
212			};
213			window.addEventListener("manual-scroll", this._manualScrollHandler);
214	
215			this._autoScrollStartHandler = () => {
216				this.isAutoScrolling = true;
217			};
218			this._autoScrollEndHandler = () => {
219				this.isAutoScrolling = false;
220			};
221			window.addEventListener("auto-scroll-start", this._autoScrollStartHandler);
222			window.addEventListener("auto-scroll-end", this._autoScrollEndHandler);
223	
224			// Word menu actions (dispatched by WordMenu when user picks "Play from here", etc.)
225			this._wordActionHandler = ({ detail }) => {
226				if (detail.kind === "play") this.seekToWordIndex(detail.index);
227			};
228			window.addEventListener("word-action", this._wordActionHandler);
229	
230			// Speed badge: cycle on click. No LV round-trip.
231			const speedBadge = document.getElementById("speed-badge");
232			if (speedBadge) {
233				speedBadge.addEventListener("click", () => this.cycleSpeed("up"));
234			}
235	
236			// Window events from KeyboardShortcuts (no LV round-trip).
237			this._togglePlaybackHandler = () => this.togglePlayback();
238			this._toggleMuteHandler = () => {
239				this.audio.muted = !this.audio.muted;
240			};
241			this._changeSpeedHandler = ({ detail }) =>
242				this.cycleSpeed(detail?.direction || "up");
243			window.addEventListener(
244				"audio:toggle-playback",
245				this._togglePlaybackHandler,
246			);
247			window.addEventListener("audio:toggle-mute", this._toggleMuteHandler);
248			window.addEventListener("audio:change-speed", this._changeSpeedHandler);
249	
250			this.setupIntersectionObserver();
251		},
252	
253		cycleSpeed(direction) {
254			const speeds = [0.5, 0.75, 1, 1.25, 1.5, 1.75, 2];
255			const cur = this.audio.playbackRate;
256			const idx = speeds.findIndex((s) => Math.abs(s - cur) < 0.01);
257			const next =
258				direction === "up"
259					? speeds[Math.min(speeds.length - 1, idx + 1)]
260					: speeds[Math.max(0, idx - 1)];
261			this.setSpeed(next);
262		},
263	
264		applyAudioPrefs() {
265			this.audio.playbackRate = this.prefs.speed;
266			this.audio.volume = this.prefs.volume;
267		},
268	
269		setupScrubber(scrubber) {
270			const getPercent = (clientX) => {
271				const rect = scrubber.getBoundingClientRect();
272				if (rect.width === 0) return 0;
273				return Math.min(1, Math.max(0, (clientX - rect.left) / rect.width));
274			};
275	
276			const seek = (clientX) => {
277				if (this.audio.duration && Number.isFinite(this.audio.duration)) {
278					const pct = getPercent(clientX);
279					this.audio.currentTime = pct * this.audio.duration;
280				}
281			};
282	
283			scrubber.addEventListener("click", (e) => seek(e.clientX));
284	
285			let isDragging = false;
286			scrubber.addEventListener("mousedown", (e) => {
287				isDragging = true;
288				seek(e.clientX);
289				e.preventDefault();
290			});
291			const onMouseMove = (e) => {
292				if (isDragging) seek(e.clientX);
293			};
294			const onMouseUp = () => {
295				isDragging = false;
296			};
297			window.addEventListener("mousemove", onMouseMove);
298			window.addEventListener("mouseup", onMouseUp);
299			this._scrubberCleanups.push(() => {
300				window.removeEventListener("mousemove", onMouseMove);
301				window.removeEventListener("mouseup", onMouseUp);
302			});
303	
304			scrubber.addEventListener(
305				"touchstart",
306				(e) => {
307					e.preventDefault();
308					seek(e.touches[0].clientX);
309				},
310				{ passive: false },
311			);
312			scrubber.addEventListener(
313				"touchmove",
314				(e) => {
315					e.preventDefault();
316					seek(e.touches[0].clientX);
317				},
318				{ passive: false },
319			);
320			scrubber.addEventListener(
321				"touchend",
322				(e) => {
323					e.preventDefault();
324					if (e.changedTouches[0]) seek(e.changedTouches[0].clientX);
325				},
326				{ passive: false },
327			);
328		},
329	
330		seekToWordIndex(idx) {
331			if (idx < 0 || idx >= this.timings.length) return;
332			this.audio.currentTime = this.timings[idx].start_ms / 1000;
333			if (this.audio.paused) this.audio.play();
334		},
335	
336		setupIntersectionObserver() {
337			if (!this.textContainer || !window.IntersectionObserver) return;
338			this._intersectionObserver = new IntersectionObserver(
339				(entries) => {
340					entries.forEach((entry) => {
341						if (entry.isIntersecting && this.autoScrollPaused) {
342							this.autoScrollPaused = false;
343							if (this.resyncBtn) this.resyncBtn.classList.add("hidden");
344						}
345					});
346				},
