1	export const ScrollTracker = {
2		mounted() {
3			// Restore scroll position
4			const initial = parseFloat(this.el.dataset.initialScroll || "0");
5			if (initial > 0) {
6				requestAnimationFrame(() => {
7					this.el.scrollTop =
8						initial * (this.el.scrollHeight - this.el.clientHeight);
9				});
10			}
11	
12			// Track whether auto-scroll is in progress (dispatched by AudioPlayer)
13			this._isAutoScrolling = false;
14			this._autoScrollStartHandler = () => {
