1	const SETTINGS_KEY = "readaloud-reader-settings";
2	
3	const defaults = {
4		fontFamily: "serif",
5		fontSize: 18,
6		lineHeight: 1.8,
7		maxWidth: 700,
8		autoScroll: true,
9		autoNextChapter: false,
10	};
11	
12	const RANGE_KEYS = ["fontSize", "lineHeight", "maxWidth"];
13	
14	const ReaderSettingsHook = {
15		mounted() {
16			this.settings = {
17				...defaults,
18				...JSON.parse(localStorage.getItem(SETTINGS_KEY) || "{}"),
19			};
20			this.applySettings();
21			this.syncControls();
22			this.bindSettingsControls();
23		},
24	
25		bindSettingsControls() {
26			const popover = document.getElementById("reader-settings");
27			if (!popover) return;
28	
29			// Font family — buttons carry data-font-family.
30			this._fontHandlers = [];
31			popover.querySelectorAll("[data-font-family]").forEach((btn) => {
32				const handler = () => this.update("fontFamily", btn.dataset.fontFamily);
33				btn.addEventListener("click", handler);
34				this._fontHandlers.push([btn, handler]);
35			});
36	
37			// Range inputs — name attribute matches the settings key.
38			this._rangeHandlers = [];
39			popover.querySelectorAll("input[type=range][name]").forEach((input) => {
40				const handler = () =>
41					this.update(input.name, Number.parseFloat(input.value));
42				input.addEventListener("input", handler);
43				this._rangeHandlers.push([input, handler]);
44			});
45	
46			// Auto-next-chapter toggle.
47			const toggle = document.getElementById("auto-next-chapter-toggle");
48			if (toggle) {
49				this._autoNextHandler = () =>
50					this.update("autoNextChapter", toggle.checked);
51				toggle.addEventListener("change", this._autoNextHandler);
52			}
53		},
54	
55		update(key, value) {
56			this.settings[key] = value;
57			localStorage.setItem(SETTINGS_KEY, JSON.stringify(this.settings));
58			this.applySettings();
59		},
60	
61		syncControls() {
62			const popover = document.getElementById("reader-settings");
63			if (popover) {
64				for (const key of RANGE_KEYS) {
65					const input = popover.querySelector(`input[type=range][name="${key}"]`);
66					if (input && this.settings[key] != null)
67						input.value = this.settings[key];
68				}
69			}
70			const toggle = document.getElementById("auto-next-chapter-toggle");
71			if (toggle) toggle.checked = !!this.settings.autoNextChapter;
72		},
73	
74		applySettings() {
75			const content = document.getElementById("reader-content");
76			if (!content) return;
77	
78			const fonts = {
79				serif: "Georgia, serif",
80				sans: "'Inter', sans-serif",
81				mono: "ui-monospace, monospace",
82			};
83			content.style.maxWidth = `${this.settings.maxWidth}px`;
84	
85			const article = document.getElementById("chapter-text");
86			if (article) {
87				article.style.fontFamily = fonts[this.settings.fontFamily] || fonts.serif;
88				article.style.fontSize = `${this.settings.fontSize}px`;
89				article.style.lineHeight = this.settings.lineHeight;
90			}
91		},
92	
93		destroyed() {
94			if (this._fontHandlers) {
95				for (const [btn, handler] of this._fontHandlers) {
96					btn.removeEventListener("click", handler);
97				}
98			}
99			if (this._rangeHandlers) {
100				for (const [input, handler] of this._rangeHandlers) {
101					input.removeEventListener("input", handler);
102				}
103			}
104			const toggle = document.getElementById("auto-next-chapter-toggle");
105			if (toggle && this._autoNextHandler) {
106				toggle.removeEventListener("change", this._autoNextHandler);
107			}
108		},
109	};
110	
111	export default ReaderSettingsHook;
